function mostFrequentElement(nums) {
  const freq = new Map();
  let maxFreq = 0;
  let result = nums[0];

  for (const num of nums) {
    freq.set(num, (freq.get(num) || 0) + 1);
    const count = freq.get(num);
    if (count > maxFreq || (count === maxFreq && num < result)) {
      maxFreq = count;
      result = num;
    }
  }

  return result;
}

