def most_frequent_element(nums):
    freq = {}
    max_freq = 0
    result = nums[0]

    for num in nums:
        freq[num] = freq.get(num, 0) + 1
        count = freq[num]
        if count > max_freq or (count == max_freq and num < result):
            max_freq = count
            result = num

    return result
